#include <stdio.h>

typedef struct IndexEntry {
    int key;
    void* pointer;
} IndexEntry;

typedef struct IndexBlock {
    int count;
    IndexEntry entries[100];
} IndexBlock;

// Search in multi-level index
void* multiLevelSearch(IndexBlock** indexLevels, 
                        int numLevels, 
                        int targetKey) {
    IndexBlock* currentBlock = indexLevels[0];
    int level = 0;

    // Traverse from top level to data
    while (level < numLevels - 1) {
        // Binary search within current index block
        int left = 0, right = currentBlock->count - 1;

        while (left < right) {
            int mid = (left + right + 1) / 2;
            if (currentBlock->entries[mid].key <= targetKey)
                left = mid;
            else
                right = mid - 1;
        }

        // Move to next level
        currentBlock = (IndexBlock*)currentBlock->entries[left].pointer;
        level++;
    }

    // Search at data level (leaf index)
    // Return pointer to actual data record
    return currentBlock->entries[left].pointer;
}
